class Solution {
   public int lengthOfLIS(int[] nums) {
 int n = nums.length;
 if (n < 2) { return nums.length; }

 int[] dp = new int[n];
 Arrays.fill(dp, 1); // 1 because every number to itself is an increasing subsequence of minimum length

 for (int i = 0; i < n; i++) {
 for (int j = 0; j < i; j++) {
 if (nums[i] > nums[j]) {
 dp[i] = Math.max(dp[i], dp[j] + 1);
 }
 }
 }

 int maxLength = 0;
 for (int num : dp) {
 maxLength = Math.max(maxLength, num);
 }

 return maxLength;
   }
}

