    List<String> priorityNames = new ArrayList<>();

    List<?extends PriorityConverterStepState> targetStatesWithDisabledTransits = state.stream()
            .filter(emptyState->emptyState.hasDisabledTransits())
            .collect(Collectors.toList());

    List<? extends PriorityConverterStep> priorityConverters = state.stream()
            .filter(emptyState -> !targetStatesWithDisabledTransits.contains(emptyState.getPriorityConverter()))
            .map(emptyState -> emptyState.getPriorityConverter())
            .collect(Collectors.toList());

    for (PriorityConverterStepState state : state) {
        List<SystemTransitStep> steps = doConvertPriority(state, priorityConverters);
        for (SystemTransitStep step : steps) {
            if (!step.getTargetStates().isEmpty()) {
                for (PriorityConverterStepState targetState : step.getTargetStates()) {
                    priorityNames.add(targetState.getName());
