import sys
import os
import shutil

def concatenate_files(input_files, output_file):
    if not output_file:
        if not len(input_files):
            raise ValueError("At least one input file must be provided")
        output_file = os.path.join(os.getcwd(), os.path.basename(sys.argv[0]) + ".txt")

    with open(output_file, 'wb') as f:
        for file in input_files:
            shutil.copyfile(file, f)

if __name__ == '__main__':
    from argparse import ArgumentParser

    parser = ArgumentParser(description='Concatenate a list of files into a single file.')
    parser.add_argument('input_files', nargs='+', help='Input files to concatenate')
    parser.add_argument('-o', '--output', help='Output file name (will be created if not provided)', default=None)
    args = parser.parse_args()

    if args.output:
        output_file = args.output
    else:
        output_file = 'concatenated_file.txt'

    concatenate_files(args.input_files, output_file)

